select sach.id as rowId ,sach.no as no, sach.name as name, csct.name as conferenceTypeName, sach.subject as subject,csy.name as yearName,sach.direction as direction, huser.name as conferenceHeadName,csl.name as cityName, sach.outnum_of_people as outnumOfPeople,sach.conference_phone,sach.contact_address as contactAddress, sach.number_of_people as numberOfPeople,sach.open_date as openDate,sach.close_date as closeDate, sach.travel_flag as travelFlag,sach.fapiao_supplied as fapiaoSupplied,sach.remark as remark,sach.intro as intro, sdept.name as deptName,csru.name as hostUnitName, csru2.name as assistUnitName,ddept.name as divisionCodeName, sclass.name as disciplineClassName,suser.name as subUserName, sach.sub_date as subDate, fdiscipline.name as disciplineCodeName, sach.register_fee_amt as registerFeeAmt,sach.budget_funds_amt as budgetFundsAmt, sach.paper_num as paperNum,sach.register_start_date as registerStartDate,sach.register_end_date as registerEndDate, sach.data_status as dataStatus,sach.create_time,suser1.name as creatorName from srm_ac_conference_host sach left join ct_srm_conference_type csct on csct.code= sach.conference_type left join ct_srm_year csy on csy.code=sach.year left join ct_srm_user huser on huser.id=sach.conference_head left join ct_srm_user suser on suser.id=sach.sub_user_id left join ct_srm_user suser1 on suser1.id=sach.creator_id left join ct_srm_location csl on csl.code=sach.city left join ct_srm_dept sdept on sdept.id=sach.dept_code left join ct_srm_rely_unit csru on csru.code=sach.host_unit left join ct_srm_rely_unit csru2 on csru2.code=sach.assist_unit left join ct_srm_dept ddept on ddept.id=sach.division_code left join ct_srm_class sclass on sclass.code=sach.discipline_class left join ct_srm_discipline fdiscipline on fdiscipline.code=sach.discipline_code where (sach.sub_user_id=#{acConferenceHostDto.userId} or sach.creator_id=#{acConferenceHostDto.userId} or sach.conference_head=#{acConferenceHostDto.userId})
and sach.data_status = #{acConferenceHostDto.dataStatus}
and sach.name LIKE CONCAT('%', #{acConferenceHostDto.name}, '%')
and sach.sub_date >= #{acConferenceHostDto.startDate}
and sach.sub_date <= #{acConferenceHostDto.endDate}
and sach.no = #{acConferenceHostDto.no}
and sach.year = #{acConferenceHostDto.year}
order by sach.id desc

select sach.id as rowId ,sach.no as no, sach.name as name,csct.name as conferenceTypeName, sach.subject as subject,csy.name as yearName,sach.direction as direction,sach.sub_date as subDate,csu.name as subUserName, huser.name as conferenceHeadName,csl.name as cityName, sach.outnum_of_people as outnumOfPeople,sach.conference_phone as conferencePhone,sach.contact_address as contactAddress, sach.number_of_people as numberOfPeople,sach.open_date as openDate,sach.close_date as closeDate, sach.travel_flag as travelFlag,sach.fapiao_supplied as fapiaoSupplied,sach.remark as remark,sach.intro as intro, sdept.name as deptName,csru.name as hostUnitName, csru2.name as assistUnitName,ddept.name as divisionCodeName, sclass.name as disciplineClassName, fdiscipline.name as disciplineCodeName, sach.register_fee_amt as registerFeeAmt,sach.budget_funds_amt as budgetFundsAmt, sach.paper_num as paperNum,sach.register_start_date as registerStartDate,sach.register_end_date as registerEndDate, sach.data_status as dataStatus from srm_ac_conference_host sach left join ct_srm_conference_type csct on csct.code= sach.conference_type left join ct_srm_user csu on csu.id=sach.sub_user_id left join ct_srm_year csy on csy.code=sach.year left join ct_srm_user huser on huser.id=sach.conference_head left join ct_srm_location csl on csl.code=sach.city left join ct_srm_dept sdept on sdept.id=sach.dept_code left join ct_srm_rely_unit csru on csru.code=sach.host_unit left join ct_srm_rely_unit csru2 on csru2.code=sach.assist_unit left join ct_srm_dept ddept on ddept.id=sach.division_code left join ct_srm_class sclass on sclass.code=sach.discipline_class left join ct_srm_discipline fdiscipline on fdiscipline.code=sach.discipline_code left join cf_srm_eaf_rec eafrec on eafrec.sys_no="P032" and eafrec.check_rec_id=sach.id where eafrec.step_no>1
and sach.name LIKE CONCAT('%', #{acConferenceHostDto.name}, '%')
and sach.sub_date >= #{acConferenceHostDto.startDate}
and sach.sub_date <= #{acConferenceHostDto.startDate}
and sach.no = #{acConferenceHostDto.no}
and sach.year = #{acConferenceHostDto.year}
and ( (sach.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{acConferenceHostDto.userId}, '|%')) or (eafrec.step_no = (select max(step_no) from cf_srm_eaf_rec seafrec where seafrec.sys_no="P032" and seafrec.check_rec_id=sach.id) and eafrec.checker_string LIKE CONCAT('%|', #{acConferenceHostDto.userId}, '|%') and eafrec.check_datetime is not null) or (sach.data_status=0 and eafrec.is_current_step=1 and eafrec.check_result=3 and eafrec.checker_string LIKE CONCAT('%|', #{acConferenceHostDto.userId}, '|%')) )
and sach.data_status=1 and eafrec.is_current_step=1 and eafrec.checker_string LIKE CONCAT('%|', #{acConferenceHostDto.userId}, '|%')
and sach.data_status=1 and eafrec.check_result="2" and eafrec.checker_string LIKE CONCAT('%|', #{acConferenceHostDto.userId}, '|%')
and sach.data_status=0 and eafrec.check_result="3" and eafrec.checker_string LIKE CONCAT('%|', #{acConferenceHostDto.userId}, '|%')
